<template>
  <div class="search">
    <div class="search__wrapper">
      <input
          type="text"
          class="search__inp"
          placeholder="Поиск . . ."
          v-model="search"
          @input="searchResult($event.target.value)"
      />
      <button class="search__btn"></button>

<!--            <button class="search__btn" v-if="!voice"></button>-->
<!--            <button-->
<!--              class="search__btn search__btn_voice"-->
<!--              v-if="voice"-->
<!--              @click="voiceSearch"-->
<!--            ></button>-->
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      voice: false,
      search: "",
    };
  },
  mounted() {
    if (
        window.SpeechRecognition ||
        window.webkitSpeechRecognition ||
        window.mozSpeechRecognition ||
        window.msSpeechRecognition
    ) {
      this.voice = true;
    } else {
      console.log("Распознавание голоса не поддерживается данным браузером");
    }
  },
  methods: {
    voiceSearch() {
      // Создаем распознаватель
      let recognizer = new (window.SpeechRecognition || window.webkitSpeechRecognition || window.mozSpeechRecognition || window.msSpeechRecognition)();

      // Ставим опцию, чтобы распознавание началось ещё до того, как пользователь закончит говорить
      recognizer.interimResults = true;

      // Какой язык будем распознавать?
      recognizer.lang = "ru-Ru";

      // Используем колбек для обработки результатов
      recognizer.onresult = () => this.myVoice(event);

      // Начинаем слушать микрофон и распознавать голос
      recognizer.start();
    },
    myVoice(event) {
      let result = event.results[event.resultIndex];
      if (result.isFinal) {
        console.log("Вы сказали: " + result[0].transcript);
        this.search = result[0].transcript;
        this.$emit('searchTasks', this.search)

        if (result[0].transcript.toLowerCase() == "добавить задачу") {
          this.$emit("voiceAddTask");
        }
      } else {
        console.log("Промежуточный результат: ", result[0].transcript);
        this.search = result[0].transcript;
        if (result[0].transcript.toLowerCase() == "добавить задачу") {
          this.$emit("voiceAddTask");
        }
      }
    },
    searchResult(value) {
      this.search = value;
      this.$emit('searchTasks', value)
    },
  },
};
</script>

